/* harmony default export */ var ChangePasswordvue_type_script_lang_js = ({
  props: {
    userid: {
      type: Number,
      required: null,
      default: null
    }
  },

  data() {
    return {
      current_password: '',
      validationPassword: false,
      passwordType: true,
      new_password: '',
      validationPassword2: false,
      passwordType2: true,
      confirm_password: '',
      // validationPassword3: false,
      passwordType3: true,
      showMessage: false,
      messageError: '',
      score: ''
    };
  },

  computed: {
    validationBtnSave() {
      if (this.current_password.length >= 8 && this.new_password.length >= 8 && this.confirm_password.length >= 8 && !this.validationPassword3) {
        return true;
      } else {
        return false;
      }
    },

    validationPassword3() {
      if (this.confirm_password.length > 0) {
        if (this.confirm_password !== this.new_password) {
          return true;
        } else {
          return false;
        }
      } else {
        return false;
      }
    }

  },
  methods: {
    onScore({
      score,
      strength
    }) {
      if (score === 0 || score === 1) {
        this.score = 'Weak';
      }

      if (score === 2 || score === 3) {
        this.score = 'Moderate';
      }

      if (score === 4) {
        this.score = 'Strong';
      }
    },

    closeDialog() {
      document.querySelector('body').style.overflow = '';
      this.$store.commit('user/SET_USER_PASSWORD_CHANGE_DIALOG', false);
      this.clearForm();
    },

    clearForm() {
      this.new_password = '';
      this.confirm_password = '';
      this.current_password = '';
    },

    save() {
      this.$notifier.showMessage({
        content: 'Saving changes...',
        type: 'loading'
      });
      const data = {
        oldPassword: this.current_password,
        newPassword: this.new_password,
        confirmNewPassword: this.confirm_password,
        userId: this.userid
      };
      console.log('datanya', data);
      const x = setTimeout(() => this.$store.dispatch('user/userChangePassword', data).then(res => {
        if (res.status === 201 || res.status === 200) {
          // this.$router.push({ path: '/campaign' })
          this.$notifier.showMessage({
            content: 'Password changed!.',
            type: 'success'
          });
          document.querySelector('body').style.overflow = '';
          this.$store.commit('user/SET_USER_PASSWORD_CHANGE_DIALOG', false);
          clearInterval(x);
        } else {
          if (res.data.data.message === 'Incorrect Password') {
            this.validationPassword = true;
            this.messageError = 'Incorrect Password';
          } else {
            this.showMessage = true;
            this.messageError = res.data.data.message;
          }

          clearInterval(x);
        }
      }).catch(() => {
        clearInterval(x);
      }), 1000);
    }

  }
});
